     1→use std::path::{Path, PathBuf};
     2→use std::time::Duration;
     3→
     4→use anyhow::{bail, Context};
     5→use lettre::{
     6→    message::{header::ContentType, Attachment, MultiPart, SinglePart},
     7→    transport::smtp::authentication::Credentials,
     8→    Message, SmtpTransport, Transport,
     9→};
    10→use serde::Deserialize;
    11→
    12→const XKCD_API_URL: &str = "https://xkcd.com/info.0.json";
    13→const HISTORY_FILE: &str = "xkcd_history.txt";
    14→const COMIC_DIR: &str = "comics";
    15→
    16→#[derive(Debug, Deserialize)]
    17→struct Comic {
    18→    num: u32,
    19→    safe_title: String,
    20→    img: String,
    21→    alt: String,
    22→    year: String,
    23→    month: String,
    24→    day: String,
    25→}
    26→
    27→#[derive(Debug)]
    28→struct Config {
    29→    mail_to: String,
    30→    mail_from: String,
    31→    download: bool,
    32→    mail_attachment: bool,
    33→    smtp_server: String,
    34→    smtp_port: u16,
    35→    smtp_starttls: bool,
    36→    smtp_username: Option<String>,
    37→    smtp_password: Option<String>,
    38→}
    39→
    40→fn load_config() -> anyhow::Result<Config> {
    41→    let _ = dotenvy::dotenv();
    42→
    43→    fn env(key: &str) -> anyhow::Result<String> {
    44→        std::env::var(key).with_context(|| format!("missing env var {key}"))
    45→    }
    46→
    47→    fn env_bool(key: &str, default: bool) -> bool {
    48→        match std::env::var(key) {
    49→            Ok(v) => matches!(v.trim().to_ascii_lowercase().as_str(), "true" | "1" | "yes"),
    50→            Err(_) => default,
    51→        }
    52→    }
    53→
    54→    let config = Config {
    55→        mail_to: env("XKCD_MAIL_TO")?,
    56→        mail_from: env("XKCD_MAIL_FROM")?,
    57→        download: env_bool("XKCD_DOWNLOAD", true),
    58→        mail_attachment: env_bool("XKCD_MAIL_ATTACHMENT", false),
    59→        smtp_server: env("XKCD_SMTP_SERVER")?,
    60→        smtp_port: std::env::var("XKCD_SMTP_PORT")
    61→            .unwrap_or_else(|_| "587".into())
    62→            .parse()
    63→            .context("XKCD_SMTP_PORT must be a number")?,
    64→        smtp_starttls: env_bool("XKCD_SMTP_STARTTLS", true),
    65→        smtp_username: std::env::var("XKCD_SMTP_USERNAME").ok(),
    66→        smtp_password: std::env::var("XKCD_SMTP_PASSWORD").ok(),
    67→    };
    68→
    69→    if config.mail_attachment && !config.download {
    70→        bail!("XKCD_DOWNLOAD must be true when XKCD_MAIL_ATTACHMENT is true");
    71→    }
    72→    if config.smtp_username.is_some() != config.smtp_password.is_some() {
    73→        bail!("XKCD_SMTP_USERNAME and XKCD_SMTP_PASSWORD must both be set or both be unset");
    74→    }
    75→
    76→    Ok(config)
    77→}
    78→
    79→fn fetch_comic(client: &reqwest::blocking::Client) -> anyhow::Result<Comic> {
    80→    let comic = client
    81→        .get(XKCD_API_URL)
    82→        .send()
    83→        .context("failed to reach xkcd API")?
    84→        .error_for_status()
    85→        .context("xkcd API returned error status")?
    86→        .json::<Comic>()
    87→        .context("failed to parse xkcd JSON")?;
    88→    log::debug!("fetched comic #{}: {}", comic.num, comic.safe_title);
    89→    Ok(comic)
    90→}
    91→
    92→fn is_seen(comic: &Comic) -> anyhow::Result<bool> {
    93→    let num_str = comic.num.to_string();
    94→    match std::fs::read_to_string(HISTORY_FILE) {
    95→        Ok(contents) => Ok(contents.lines().any(|line| line.trim() == num_str)),
    96→        Err(e) if e.kind() == std::io::ErrorKind::NotFound => Ok(false),
    97→        Err(e) => Err(e).context("failed to read history file"),
    98→    }
    99→}
   100→
   101→fn local_filename(comic: &Comic) -> String {
   102→    let basename = comic.img.rsplit('/').next().unwrap_or(comic.img.as_str());
   103→    format!("{}-{}", comic.num, basename)
   104→}
   105→
   106→fn download_image(client: &reqwest::blocking::Client, comic: &Comic) -> anyhow::Result<PathBuf> {
   107→    std::fs::create_dir_all(COMIC_DIR).context("failed to create comics directory")?;
   108→
   109→    let filename = local_filename(comic);
   110→    let dest = Path::new(COMIC_DIR).join(&filename);
   111→
   112→    let bytes = client
   113→        .get(&comic.img)
   114→        .send()
   115→        .context("failed to fetch comic image")?
   116→        .error_for_status()
   117→        .context("image URL returned error status")?
   118→        .bytes()
   119→        .context("failed to read image bytes")?;
   120→
   121→    std::fs::write(&dest, &bytes).with_context(|| format!("failed to write {}", dest.display()))?;
   122→
   123→    log::info!("downloaded {filename}");
   124→    Ok(dest)
   125→}
   126→
   127→fn format_date(comic: &Comic) -> anyhow::Result<String> {
   128→    let year: i32 = comic.year.parse().context("invalid year")?;
   129→    let month: u32 = comic.month.parse().context("invalid month")?;
   130→    let day: u32 = comic.day.parse().context("invalid day")?;
   131→
   132→    let date = chrono::NaiveDate::from_ymd_opt(year, month, day)
   133→        .with_context(|| format!("invalid date {year}-{month}-{day}"))?;
   134→
   135→    Ok(date.format("%a %d %b %y").to_string())
   136→}
   137→
   138→fn build_transport(config: &Config) -> anyhow::Result<SmtpTransport> {
   139→    let builder = if config.smtp_starttls {
   140→        SmtpTransport::starttls_relay(&config.smtp_server)
   141→            .context("failed to create STARTTLS transport")?
   142→    } else {
   143→        SmtpTransport::relay(&config.smtp_server)
   144→            .context("failed to create SMTP relay transport")?
   145→    };
   146→
   147→    let builder = builder.port(config.smtp_port);
   148→
   149→    let builder = match (&config.smtp_username, &config.smtp_password) {
   150→        (Some(user), Some(pass)) => {
   151→            builder.credentials(Credentials::new(user.clone(), pass.clone()))
   152→        }
   153→        _ => builder,
   154→    };
   155→
   156→    Ok(builder.build())
   157→}
   158→
   159→fn escape_html(s: &str) -> String {
   160→    let mut out = String::with_capacity(s.len());
   161→    for c in s.chars() {
   162→        match c {
   163→            '&' => out.push_str("&amp;"),
   164→            '<' => out.push_str("&lt;"),
   165→            '>' => out.push_str("&gt;"),
   166→            '"' => out.push_str("&quot;"),
   167→            '\'' => out.push_str("&#39;"),
   168→            _ => out.push(c),
   169→        }
   170→    }
   171→    out
   172→}
   173→
   174→fn send_email(
   175→    config: &Config,
   176→    comic: &Comic,
   177→    attachment_path: Option<&Path>,
   178→) -> anyhow::Result<()> {
   179→    let date_str = format_date(comic)?;
   180→    let subject = format!(
   181→        "New xkcd {}: {} from {}",
   182→        comic.num, comic.safe_title, date_str
   183→    );
   184→    let comic_url = format!("https://xkcd.com/{}/", comic.num);
   185→    let plain_text = format!("{}\n{}\n\n{}", comic.safe_title, comic_url, comic.alt);
   186→    let html_body = format!(
   187→        r#"<html><body>
   188→<h1><a href="{url}"><img title="{alt}" alt="{title}" style="display:block" src="{img}" /></a></h1>
   189→<p>{alt}</p>
   190→<br>
   191→Mailed by <a href="https://github.com/bryanhiestand/ferrous-comics">ferrous-comics</a>
   192→</body></html>"#,
   193→        url = escape_html(&comic_url),
   194→        img = escape_html(&comic.img),
   195→        title = escape_html(&comic.safe_title),
   196→        alt = escape_html(&comic.alt),
   197→    );
   198→
   199→    let alternative = MultiPart::alternative()
   200→        .singlepart(SinglePart::plain(plain_text))
   201→        .singlepart(SinglePart::html(html_body));
   202→
   203→    let body = if let Some(path) = attachment_path {
   204→        let filename = local_filename(comic);
   205→        let image_bytes = std::fs::read(path)
   206→            .with_context(|| format!("failed to read attachment {}", path.display()))?;
   207→        let content_type = match path.extension().and_then(|e| e.to_str()) {
   208→            Some("png") => ContentType::parse("image/png").unwrap(),
   209→            Some("jpg") | Some("jpeg") => ContentType::parse("image/jpeg").unwrap(),
   210→            Some("gif") => ContentType::parse("image/gif").unwrap(),
   211→            _ => ContentType::parse("application/octet-stream").unwrap(),
   212→        };
   213→        MultiPart::mixed()
   214→            .multipart(alternative)
   215→            .singlepart(Attachment::new(filename).body(image_bytes, content_type))
   216→    } else {
   217→        alternative
   218→    };
   219→
   220→    let email = Message::builder()
   221→        .from(
   222→            config
   223→                .mail_from
   224→                .parse()
   225→                .context("invalid XKCD_MAIL_FROM address")?,
   226→        )
   227→        .to(config
   228→            .mail_to
   229→            .parse()
   230→            .context("invalid XKCD_MAIL_TO address")?)
   231→        .subject(&subject)
   232→        .multipart(body)
   233→        .context("failed to build email message")?;
   234→
   235→    let transport = build_transport(config)?;
   236→    transport.send(&email).context("SMTP send failed")?;
   237→
   238→    log::info!("emailed comic #{}: {}", comic.num, comic.safe_title);
   239→    Ok(())
   240→}
   241→
   242→fn record_seen(comic: &Comic) -> anyhow::Result<()> {
   243→    use std::io::Write;
   244→    let mut file = std::fs::OpenOptions::new()
   245→        .create(true)
   246→        .append(true)
   247→        .open(HISTORY_FILE)
   248→        .context("failed to open history file for writing")?;
   249→    writeln!(file, "{}", comic.num).context("failed to write to history file")?;
   250→    Ok(())
   251→}
   252→
   253→fn main() -> anyhow::Result<()> {
   254→    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or("info")).init();
   255→
   256→    let config = load_config()?;
   257→
   258→    let client = reqwest::blocking::Client::builder()
   259→        .user_agent("ferrous-comics/0.1")
   260→        .connect_timeout(Duration::from_secs(30))
   261→        .timeout(Duration::from_secs(60))
   262→        .build()
   263→        .context("failed to build HTTP client")?;
   264→
   265→    let comic = fetch_comic(&client)?;
   266→
   267→    if is_seen(&comic)? {
   268→        log::info!("comic #{} already seen, exiting", comic.num);
   269→        return Ok(());
   270→    }
   271→
   272→    let image_path = if config.download {
   273→        Some(download_image(&client, &comic)?)
   274→    } else {
   275→        None
   276→    };
   277→
   278→    let attachment_path = if config.mail_attachment {
   279→        image_path.as_deref()
   280→    } else {
   281→        None
   282→    };
   283→
   284→    send_email(&config, &comic, attachment_path)?;
   285→    record_seen(&comic)?;
   286→
   287→    Ok(())
   288→}
