        std::fs::read_to_string(&path).context("failed to read legacy history file for migration")?;
    let nums: Vec<u32> = contents
        .lines()
        .filter(|l| !l.trim().is_empty())
        .map(|l| l.trim().parse::<u32>())
        .collect::<Result<_, _>>()
        .context("invalid comic number in legacy history file")?;

    let count = nums.len();
    let wtx = db.begin_write().context("failed to begin migration write transaction")?;
    {
        let mut table = wtx
            .open_table(COMICS_TABLE)
            .context("failed to open comics table for migration")?;
